'use client';

import { useEffect, useMemo, useState } from 'react';
import Image from 'next/image';
import Link from 'next/link';
import { Layers3, Package, Sparkles } from 'lucide-react';
import CooperativeList from '../../components/CooperativeList';
import ExploreMap from '../../components/Map';
import { cooperatives } from '../../data/mockData';
import { useCooperativeStore } from '../../store/useCooperativeStore';

export default function ExplorePage() {
  const [selectedZone, setSelectedZone] = useState('Toutes');
  const [selectedCategory, setSelectedCategory] = useState('Toutes');
  const activeCooperativeId = useCooperativeStore((state) => state.activeCooperativeId);
  const setActiveCooperativeId = useCooperativeStore((state) => state.setActiveCooperativeId);

  const zones = useMemo(() => {
    const uniqueZones = Array.from(new Set(cooperatives.map((cooperative) => cooperative.zone)));
    return ['Toutes', ...uniqueZones];
  }, []);

  const categories = useMemo(() => {
    const uniqueCategories = Array.from(
      new Set(cooperatives.map((cooperative) => cooperative.category)),
    );
    return ['Toutes', ...uniqueCategories];
  }, []);

  const filteredCooperatives = useMemo(() => {
    return cooperatives.filter((cooperative) => {
      const zoneMatch = selectedZone === 'Toutes' || cooperative.zone === selectedZone;
      const categoryMatch =
        selectedCategory === 'Toutes' || cooperative.category === selectedCategory;
      return zoneMatch && categoryMatch;
    });
  }, [selectedZone, selectedCategory]);

  useEffect(() => {
    if (!activeCooperativeId) return;

    const existsInFilteredList = filteredCooperatives.some(
      (cooperative) => cooperative.id === activeCooperativeId,
    );
    if (!existsInFilteredList) {
      setActiveCooperativeId(null);
    }
  }, [activeCooperativeId, filteredCooperatives, setActiveCooperativeId]);

  const totalProducts = filteredCooperatives.reduce((count, cooperative) => {
    return count + cooperative.products.length;
  }, 0);

  const productsCatalog = useMemo(() => {
    return filteredCooperatives.flatMap((cooperative) =>
      cooperative.products.map((product) => ({
        ...product,
        cooperativeId: cooperative.id,
        cooperativeName: cooperative.name,
        cooperativeSlug: cooperative.slug,
        zone: cooperative.zone,
      })),
    );
  }, [filteredCooperatives]);

  const zoneOverview = useMemo(() => {
    const bucket = new globalThis.Map<string, { cooperativeCount: number; productCount: number }>();
    for (const cooperative of filteredCooperatives) {
      const current = bucket.get(cooperative.zone) ?? { cooperativeCount: 0, productCount: 0 };
      bucket.set(cooperative.zone, {
        cooperativeCount: current.cooperativeCount + 1,
        productCount: current.productCount + cooperative.products.length,
      });
    }
    return Array.from(bucket.entries()).map(([zone, stats]) => ({ zone, ...stats }));
  }, [filteredCooperatives]);

  return (
    <section id="cooperatives" className="space-y-4">
      <div className="rounded-2xl border border-white/40 bg-white/70 p-5 shadow-lg backdrop-blur-md">
        <h1 className="text-2xl font-semibold text-palmier">Explorer les cooperatives</h1>
        <p className="mt-2 text-sm text-palmier/80">
          Cliquez sur une carte ou un marqueur pour synchroniser instantanement la selection.
        </p>
        <div className="mt-4 flex flex-wrap gap-2 text-xs">
          <span className="rounded-full bg-terracotta/10 px-3 py-1 font-medium text-terracotta">
            {filteredCooperatives.length} cooperatives
          </span>
          <span className="rounded-full bg-palmier/10 px-3 py-1 font-medium text-palmier">
            {totalProducts} produits
          </span>
          <span className="rounded-full bg-sable/20 px-3 py-1 font-medium text-palmier">
            Region Draa-Tafilalet
          </span>
        </div>
      </div>

      <div className="rounded-2xl border border-white/40 bg-white/80 p-4 shadow-sm backdrop-blur-md">
        <div className="mb-3 flex items-center gap-2 text-sm font-semibold text-palmier">
          <Layers3 size={16} className="text-terracotta" />
          Vue rapide par zone
        </div>
        <div className="grid grid-cols-2 gap-3 md:grid-cols-4">
          {zoneOverview.map((item) => (
            <button
              key={item.zone}
              onClick={() => setSelectedZone(item.zone)}
              className={`rounded-xl border px-3 py-3 text-left transition ${
                selectedZone === item.zone
                  ? 'border-terracotta/60 bg-terracotta/10'
                  : 'border-white/50 bg-fond hover:shadow-md'
              }`}
            >
              <p className="text-sm font-semibold text-palmier">{item.zone}</p>
              <p className="mt-1 text-xs text-palmier/70">
                {item.cooperativeCount} coop • {item.productCount} produits
              </p>
            </button>
          ))}
        </div>
      </div>

      <div className="rounded-2xl border border-white/40 bg-white/80 p-4 shadow-sm backdrop-blur-md">
        <div className="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
          <div className="text-sm font-medium text-palmier">Filtrer les cooperatives</div>
          <div className="flex flex-col gap-2 sm:flex-row">
            <label className="inline-flex items-center gap-2 rounded-full border border-white/60 bg-fond px-3 py-2 text-sm text-palmier">
              <span className="font-medium">Zone</span>
              <select
                value={selectedZone}
                onChange={(event) => setSelectedZone(event.target.value)}
                className="min-w-[130px] bg-transparent text-sm outline-none"
              >
                {zones.map((zone) => (
                  <option key={zone} value={zone}>
                    {zone}
                  </option>
                ))}
              </select>
            </label>

            <label className="inline-flex items-center gap-2 rounded-full border border-white/60 bg-fond px-3 py-2 text-sm text-palmier">
              <span className="font-medium">Categorie</span>
              <select
                value={selectedCategory}
                onChange={(event) => setSelectedCategory(event.target.value)}
                className="min-w-[140px] bg-transparent text-sm outline-none"
              >
                {categories.map((category) => (
                  <option key={category} value={category}>
                    {category}
                  </option>
                ))}
              </select>
            </label>
          </div>
        </div>
      </div>

      <div className="rounded-2xl border border-white/40 bg-white/80 p-4 shadow-sm backdrop-blur-md">
        <div className="mb-3 flex items-center gap-2 text-sm font-semibold text-palmier">
          <Sparkles size={16} className="text-terracotta" />
          Produits disponibles (catalogue general)
        </div>
        <div className="grid grid-cols-1 gap-3 sm:grid-cols-2 xl:grid-cols-4">
          {productsCatalog.slice(0, 12).map((product) => (
            <Link
              key={product.id}
              href={`/cooperative/${product.cooperativeSlug}`}
              className="group overflow-hidden rounded-xl border border-white/50 bg-fond transition hover:-translate-y-0.5 hover:shadow-lg"
            >
              <div className="relative h-32">
                <Image
                  src={product.image}
                  alt={product.alt}
                  fill
                  sizes="(max-width: 768px) 100vw, 25vw"
                  className="object-cover transition duration-300 group-hover:scale-105"
                />
              </div>
              <div className="space-y-1 p-3">
                <p className="line-clamp-1 text-sm font-semibold text-palmier">{product.name}</p>
                <p className="line-clamp-1 text-xs text-palmier/70">
                  {product.zone} • {product.cooperativeName}
                </p>
                <p className="inline-flex items-center gap-1 text-xs font-medium text-terracotta">
                  <Package size={12} />
                  {product.price} MAD
                </p>
              </div>
            </Link>
          ))}
        </div>
      </div>

      <div className="grid grid-cols-1 gap-4 lg:grid-cols-[1.6fr_1fr]">
        <ExploreMap cooperatives={filteredCooperatives} />
        <CooperativeList cooperatives={filteredCooperatives} />
      </div>
    </section>
  );
}
